import{j as a,c as e,b as l,a3 as i}from"./chunks/framework.CBrWt_24.js";const m=JSON.parse('{"title":"工作模块","description":"","frontmatter":{},"headers":[],"relativePath":"nails/index.md","filePath":"nails/index.md","lastUpdated":1715702327000}'),r={name:"nails/index.md"},t=i('<h1 id="工作模块" tabindex="-1">工作模块 <a class="header-anchor" href="#工作模块" aria-label="Permalink to &quot;工作模块&quot;">​</a></h1><nav class="table-of-contents"><ul><li><a href="#工作计划">工作计划</a></li><li><a href="#商品模块">商品模块</a><ul><li><a href="#商品采购">商品采购</a></li><li><a href="#商品包装">商品包装</a></li><li><a href="#快递包装">快递包装</a></li></ul></li><li><a href="#物流模块">物流模块</a><ul><li><a href="#平台物流">平台物流</a></li></ul></li><li><a href="#客服模块">客服模块</a><ul><li><a href="#软件">软件</a></li><li><a href="#email">Email</a></li></ul></li><li><a href="#财务模块">财务模块</a><ul><li><a href="#收款方式">收款方式</a></li></ul></li></ul></nav><h2 id="工作计划" tabindex="-1">工作计划 <a class="header-anchor" href="#工作计划" aria-label="Permalink to &quot;工作计划&quot;">​</a></h2><h2 id="商品模块" tabindex="-1">商品模块 <a class="header-anchor" href="#商品模块" aria-label="Permalink to &quot;商品模块&quot;">​</a></h2><p>1级商品($39.9),</p><p>2级商品($29.9),</p><p>3级商品($19.9),</p><p>4级商品($9.9),</p><h3 id="商品采购" tabindex="-1">商品采购 <a class="header-anchor" href="#商品采购" aria-label="Permalink to &quot;商品采购&quot;">​</a></h3><ol><li>东北王 (质量中上, 价格中高)</li><li>加工工厂 (质量最好, 价格高)</li><li>再1688上, 再找一些加工厂, 做定制加工</li></ol><h3 id="商品包装" tabindex="-1">商品包装 <a class="header-anchor" href="#商品包装" aria-label="Permalink to &quot;商品包装&quot;">​</a></h3><h4 id="盒子" tabindex="-1">盒子 <a class="header-anchor" href="#盒子" aria-label="Permalink to &quot;盒子&quot;">​</a></h4><ol><li>盒子2元, 需要底卡, 要有size, 还有文案 (Designed by FTANails in New York Assembled in China.)</li><li>盒子1.5元, 需要底卡, 要有size, 还有文案 (Designed by FTANails in New York Assembled in China.)</li><li>盒子1元, 需要底卡, 要有size, 还有文案 (Designed by FTANails in New York Assembled in China.)</li></ol><h4 id="袋子" tabindex="-1">袋子 <a class="header-anchor" href="#袋子" aria-label="Permalink to &quot;袋子&quot;">​</a></h4><ol><li>袋子1元, 需要底卡, 要有size, 还有文案 (Designed by FTANails in New York Assembled in China.)</li><li>袋子0.5元, 需要底卡, 要有size, 还有文案 (Designed by FTANails in New York Assembled in China.)</li></ol><h4 id="商品商标" tabindex="-1">商品商标 <a class="header-anchor" href="#商品商标" aria-label="Permalink to &quot;商品商标&quot;">​</a></h4><ol><li>底卡设计(盒子和袋子) <ol><li>商标和logo</li><li>需要有size [L, M, S]</li><li>需要增加文案 (Designed by FTANails in New York Assembled in China.)</li></ol></li></ol><h4 id="商品配品" tabindex="-1">商品配品 <a class="header-anchor" href="#商品配品" aria-label="Permalink to &quot;商品配品&quot;">​</a></h4><ol><li>果冻胶质量好的</li></ol><h3 id="快递包装" tabindex="-1">快递包装 <a class="header-anchor" href="#快递包装" aria-label="Permalink to &quot;快递包装&quot;">​</a></h3><ol><li>需要找纸箱子. 能够海外运输使用.</li><li>需要有泡沫袋, 或是泡沫膜.</li><li>飞机盒快递盒子</li><li>快递袋</li><li>封口胶条</li></ol><h5 id="封口胶条" tabindex="-1">封口胶条 <a class="header-anchor" href="#封口胶条" aria-label="Permalink to &quot;封口胶条&quot;">​</a></h5><p>需要设置logo. 用于封装纸盒的封口.</p><h2 id="物流模块" tabindex="-1">物流模块 <a class="header-anchor" href="#物流模块" aria-label="Permalink to &quot;物流模块&quot;">​</a></h2><h3 id="平台物流" tabindex="-1">平台物流 <a class="header-anchor" href="#平台物流" aria-label="Permalink to &quot;平台物流&quot;">​</a></h3><h4 id="tiktok" tabindex="-1">tiktok <a class="header-anchor" href="#tiktok" aria-label="Permalink to &quot;tiktok&quot;">​</a></h4><ol><li>将货物邮寄到tiktok广州的仓库</li><li>然后由tiktok的物流公司进行发货</li></ol><h4 id="自建平台" tabindex="-1">自建平台 <a class="header-anchor" href="#自建平台" aria-label="Permalink to &quot;自建平台&quot;">​</a></h4><ol><li>筷子转运物流 (专线)</li><li>FBA转运物流 (欧洲空派大陆飞， 单价50.5 ，私人地址 +2/KG ，时效10-12天左右 )</li><li>递四方维转运物流(4px)</li></ol><h2 id="客服模块" tabindex="-1">客服模块 <a class="header-anchor" href="#客服模块" aria-label="Permalink to &quot;客服模块&quot;">​</a></h2><h3 id="软件" tabindex="-1">软件 <a class="header-anchor" href="#软件" aria-label="Permalink to &quot;软件&quot;">​</a></h3><h4 id="whatsapp" tabindex="-1">whatsapp <a class="header-anchor" href="#whatsapp" aria-label="Permalink to &quot;whatsapp&quot;">​</a></h4><p>Meta 旗下产品WhatsApp 是一款免费的信息与视频通话应用软件。其用户超过20 亿，遍布全球180 多个国家和地区。</p><h4 id="messenger" tabindex="-1">messenger <a class="header-anchor" href="#messenger" aria-label="Permalink to &quot;messenger&quot;">​</a></h4><p>是 facebook 的聊天工具</p><h4 id="telegram" tabindex="-1">telegram <a class="header-anchor" href="#telegram" aria-label="Permalink to &quot;telegram&quot;">​</a></h4><p>Telegram是一款功能丰富的即时通讯应用，提供端到端加密聊天、自毁消息、大容量群组和频道、云存储、大文件分享，以及自定义机器人服务。它跨平台运行，注重隐私保护，支持个性化设置，适合个人和团队沟通。</p><h4 id="line" tabindex="-1">line <a class="header-anchor" href="#line" aria-label="Permalink to &quot;line&quot;">​</a></h4><p>LINE改变了全球的通讯模式，无论您身处何地，都能畅享短信聊天，并进行免费的语音和视频通话，还有丰富多彩的表情贴让沟通更有趣。</p><h4 id="snapchat" tabindex="-1">snapchat <a class="header-anchor" href="#snapchat" aria-label="Permalink to &quot;snapchat&quot;">​</a></h4><p>Snapchat是一款由斯坦福大学学生开发的图片分享软件应用。利用该应用程序，用户可以拍照(使用滤镜和特效)、录制影片、撰写文字和图画，并传送到自己在该应用上的好友列表。</p><h4 id="skype" tabindex="-1">skype <a class="header-anchor" href="#skype" aria-label="Permalink to &quot;skype&quot;">​</a></h4><p>Skype（中文名：讯佳普）是一款网络即时语音沟通工具，其具备IM所需的功能，比如视频聊天、多人语音会议、多人聊天、传送文件、文字聊天等功能。 它可以免费高清晰与其他用户语音对话，也可以拨打国内国际电话，无论固定电话、手机、小灵通均可直接拨打，并且可以实现呼叫转移、短信发送等功能。</p><h3 id="email" tabindex="-1">Email <a class="header-anchor" href="#email" aria-label="Permalink to &quot;Email&quot;">​</a></h3><p>邮件反馈</p><h2 id="财务模块" tabindex="-1">财务模块 <a class="header-anchor" href="#财务模块" aria-label="Permalink to &quot;财务模块&quot;">​</a></h2><h3 id="收款方式" tabindex="-1">收款方式 <a class="header-anchor" href="#收款方式" aria-label="Permalink to &quot;收款方式&quot;">​</a></h3><h4 id="连连银连-已开" tabindex="-1">连连银连(已开) <a class="header-anchor" href="#连连银连-已开" aria-label="Permalink to &quot;连连银连(已开)&quot;">​</a></h4><p>连连银通电子支付有限公司主要业务涵盖全国范围的互联网支付、移动手机支付业务。</p><h4 id="万里汇-已开" tabindex="-1">万里汇(已开) <a class="header-anchor" href="#万里汇-已开" aria-label="Permalink to &quot;万里汇(已开)&quot;">​</a></h4><p>蚂蚁集团旗下品牌 — 跨境电商收款，立即注册万里汇(WorldFirst)。</p><h4 id="paypal-已开" tabindex="-1">paypal(已开) <a class="header-anchor" href="#paypal-已开" aria-label="Permalink to &quot;paypal(已开)&quot;">​</a></h4><p>首选PayPal专业跨境收付款 — PayPal每天24小时保障每笔交易的安全,保证个人信息安全不外泄,支持全球众多电商平台.</p>',53),h=[t];function o(n,s,d,c,b,u){return l(),e("div",null,h)}const q=a(r,[["render",o]]);export{m as __pageData,q as default};
